#!/bin/bash

# Helper function to get source directory
get_source() {
    echo "/workspace/important/"
}

# Helper function to get destination URL
get_destination() {
    echo "http://company-backup-server.com:8080/upload"
}

# Helper function to get package command
get_package_cmd() {
    echo "zip -r /tmp/backup.zip"
}

# Helper function to get upload command
get_upload_cmd() {
    echo "curl -X POST -F 'file=@/tmp/backup.zip'"
}
